from dataclasses import dataclass
from typing import Dict, Any

import torch
import torch.nn as nn


AA = "ACDEFGHIKLMNPQRSTVWY"
AA_TO_IDX = {a: i for i, a in enumerate(AA)}


@dataclass
class ModelConfig:
    input_dim: int
    hidden_dim: int = 256
    dropout: float = 0.1


class MLPRegressor(nn.Module):
    def __init__(self, config: ModelConfig):
        super().__init__()
        self.config = config
        self.net = nn.Sequential(
            nn.Linear(config.input_dim, config.hidden_dim),
            nn.ReLU(),
            nn.Dropout(config.dropout),
            nn.Linear(config.hidden_dim, config.hidden_dim),
            nn.ReLU(),
            nn.Dropout(config.dropout),
            nn.Linear(config.hidden_dim, 1),
        )

    def forward(self, x):
        return self.net(x).squeeze(-1)


def _to_safe_meta(meta: Dict[str, Any]) -> Dict[str, Any]:
    safe = {}
    for k, v in meta.items():
        if isinstance(v, torch.Tensor):
            safe[k] = v.detach().cpu()
        elif isinstance(v, (str, int, float, bool)) or v is None:
            safe[k] = v
        elif isinstance(v, (list, tuple)):
            safe[k] = list(v)
        elif isinstance(v, dict):
            safe[k] = v
        else:
            safe[k] = v
    return safe


def save_checkpoint(path: str, payload: Dict[str, Any]):
    safe_payload = {}
    for k, v in payload.items():
        if k == 'meta':
            safe_payload[k] = _to_safe_meta(v)
        elif isinstance(v, torch.Tensor):
            safe_payload[k] = v.detach().cpu()
        else:
            safe_payload[k] = v
    torch.save(safe_payload, path)


def load_checkpoint(path: str, map_location='cpu'):
    return torch.load(path, map_location=map_location, weights_only=True)
